  // If the switch condition is an intrinsic ucmp/scmp, try to turn into icmp.
  if (auto *CI = dyn_cast<CallInst>(SI->getCondition())) {
    if (CI->getIntrinsicID() == Intrinsic::ucmp ||
        CI->getIntrinsicID() == Intrinsic::scmp) {
      bool IsSigned = CI->getIntrinsicID() == Intrinsic::scmp;
      Value *LHS = CI->getArgOperand(0);
      Value *RHS = CI->getArgOperand(1);
      // Determine destination for each possible result (-1, 0, 1).
      // Use a small map from value to destination.
      SmallDenseMap<ConstantInt *, BasicBlock *, 3> ValueToDest;
      for (auto &Case : SI->cases()) {
        ValueToDest[Case.getCaseValue()] = Case.getCaseSuccessor();
      }
      BasicBlock *DefaultDest = SI->getDefaultDest();
      // For each possible result value, determine destination.
      // Since the result is limited to -1,0,1, we can enumerate.
      LLVMContext &Ctx = SI->getContext();
      ConstantInt *ValM1 = ConstantInt::getSigned(CI->getType(), -1);
      ConstantInt *Val0 = ConstantInt::getSigned(CI->getType(), 0);
      ConstantInt *Val1 = ConstantInt::getSigned(CI->getType(), 1);
      BasicBlock *DestM1 = ValueToDest.lookup(ValM1);
      BasicBlock *Dest0 = ValueToDest.lookup(Val0);
      BasicBlock *Dest1 = ValueToDest.lookup(Val1);
      // If a value is not present in cases, it goes to default.
      if (!DestM1) DestM1 = DefaultDest;
      if (!Dest0) Dest0 = DefaultDest;
      if (!Dest1) Dest1 = DefaultDest;
      // Check if all three destinations are the same -> unconditional branch.
      if (DestM1 == Dest0 && Dest0 == Dest1) {
        // Should have been folded earlier.
        return false;
      }
      // Determine which destinations are distinct; we expect two.
      SmallVector<BasicBlock *, 2> Dests;
      if (DestM1 != Dest0) {
        Dests.push_back(DestM1);
        Dests.push_back(Dest0);
      }
      if (Dest0 != Dest1 && (Dests.empty() || Dests.back() != Dest1))
        Dests.push_back(Dest1);
      if (DestM1 != Dest1 && (Dests.empty() || Dests.back() != Dest1))
        Dests.push_back(Dest1);
      // Remove duplicates.
      Dests.erase(std::unique(Dests.begin(), Dests.end()), Dests.end());
      if (Dests.size() != 2) {
        // More than two destinations? Should not happen.
        return false;
      }
      BasicBlock *DestA = Dests[0];
      BasicBlock *DestB = Dests[1];
      // Determine which values map to DestA.
      SmallVector<ConstantInt *, 3> ValuesA;
      if (DestM1 == DestA) ValuesA.push_back(ValM1);
      if (Dest0 == DestA) ValuesA.push_back(Val0);
      if (Dest1 == DestA) ValuesA.push_back(Val1);
      // The other values map to DestB.
      // If ValuesA has size 1 or 2, we can produce a single icmp.
      // Map value to predicate.
      auto getPredicateForValue = [IsSigned](ConstantInt *Val) {
        int64_t V = Val->getSExtValue();
        if (V == -1) return IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
        if (V == 0) return ICmpInst::ICMP_EQ;
        if (V == 1) return IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
        llvm_unreachable("invalid ucmp/scmp result");
      };
      // Try to find a single predicate that matches all values in ValuesA.
