        SI->eraseFromParent();
        return requestResimplify();
      }
      // For size 2, we need to produce a predicate that covers both values.
      // Possible pairs: {-1,0} -> <= (ULT or SLT for -1, EQ for 0) -> LE
      // {0,1} -> >= (EQ, GT) -> GE
      // {-1,1} -> != (LT, GT) -> NE
      // Determine which pair.
      bool HasM1 = DestM1 == DestA;
      bool Has0 = Dest0 == DestA;
      bool Has1 = Dest1 == DestA;
      ICmpInst::Predicate Pred;
      if (HasM1 && Has0 && !Has1) {
        Pred = IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
      } else if (!HasM1 && Has0 && Has1) {
        Pred = IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
      } else if (HasM1 && !Has0 && Has1) {
        Pred = ICmpInst::ICMP_NE;
      } else {
        // Cannot represent as single icmp.
        return false;
      }
      Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS);
      BranchInst *NewBI = Builder.CreateCondBr(Cmp, DestA, DestB);
      SI->eraseFromParent();
      return requestResimplify();
    }
  }

